const config = $('Load Report Config').item.json;
const aiResponse = $input.item.json;

const reportContent = aiResponse.content?.[0]?.text || 'Report generation failed';

// Add branding header and footer
const brandedReport = `# ${config.title}\n\n` +
  `**Prepared for:** ${config.clientName}\n` +
  `**Date:** ${config.generationDate}\n` +
  `**Report ID:** ${config.reportId}\n` +
  `**Location:** ${config.location}\n\n` +
  `---\n\n` +
  reportContent +
  `\n\n---\n\n` +
  `*This report was prepared by our research team using proprietary data analysis tools and industry databases. ` +
  `For questions or custom analysis requests, contact us at reports@yourdomain.com.*\n`;

return [{
  json: {
    reportId: config.reportId,
    clientName: config.clientName,
    clientEmail: config.clientEmail,
    title: config.title,
    reportContent: brandedReport,
    price: config.price,
    generatedAt: new Date().toISOString(),
    wordCount: brandedReport.split(/\s+/).length
  }
}];

